using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator;

    public ScoreCalculatorTests()
    {
        _calculator = new ScoreCalculator();
    }

    // --- CalculatePercentage ---

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    [DataRow(1, 3, 33.333333333333336)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_ResultAlwaysBetween0And100()
    {
        var result = _calculator.CalculatePercentage(5, 10);

        // Use comparison assertions for boundary checks
        Assert.IsGreaterThan(0.0, result);   // result > 0
        Assert.IsLessThan(100.0, result);    // result < 100
        Assert.IsInRange(result, 0.0, 100.0); // 0 <= result <= 100
    }

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        var result = _calculator.CalculatePercentage(20, 20);

        Assert.AreEqual(100.0, result);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_Returns0()
    {
        var result = _calculator.CalculatePercentage(0, 10);

        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade ---

    [TestMethod]
    [DataRow(100.0, "A")]
    [DataRow(90.0, "A", DisplayName = "Boundary: A starts at 90")]
    [DataRow(89.99, "B")]
    [DataRow(80.0, "B", DisplayName = "Boundary: B starts at 80")]
    [DataRow(79.99, "C")]
    [DataRow(70.0, "C", DisplayName = "Boundary: C starts at 70")]
    [DataRow(69.99, "D")]
    [DataRow(60.0, "D", DisplayName = "Boundary: D starts at 60")]
    [DataRow(59.99, "F")]
    [DataRow(0.0, "F")]
    [DataRow(-5.0, "F")]
    public void GetGrade_ReturnsExpectedGrade(double percentage, string expected)
    {
        var grade = _calculator.GetGrade(percentage);

        Assert.AreEqual(expected, grade);
    }

    [TestMethod]
    public void GetGrade_AllGradesAreSingleLetter()
    {
        double[] samples = [0, 60, 70, 80, 90, 100];

        foreach (var pct in samples)
        {
            var grade = _calculator.GetGrade(pct);
            Assert.AreEqual(1, grade.Length);
            Assert.MatchesRegex(@"^[A-F]$", grade);
        }
    }

    // --- NormalizeScore ---

    [TestMethod]
    [DataRow(50.0, 100.0, 50.0)]
    [DataRow(25.0, 50.0, 50.0)]
    [DataRow(0.0, 100.0, 0.0)]
    [DataRow(100.0, 100.0, 100.0)]
    public void NormalizeScore_ValidInputs_ReturnsExpected(double raw, double maxRaw, double expected)
    {
        var result = _calculator.NormalizeScore(raw, maxRaw);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void NormalizeScore_ResultNeverExceeds100()
    {
        // Raw score exceeds max — should be capped at 100
        var result = _calculator.NormalizeScore(150.0, 100.0);

        Assert.AreEqual(100.0, result);
        Assert.IsLessThan(101.0, result); // result < 101 (at most 100)
    }

    [TestMethod]
    public void NormalizeScore_ResultIsAlwaysInRange()
    {
        var result = _calculator.NormalizeScore(30.0, 80.0);

        Assert.IsGreaterThan(0.0, result);    // result > 0
        Assert.IsLessThan(100.0, result);     // result < 100
        Assert.IsInRange(result, 0.0, 100.0); // 0 <= result <= 100
    }

    [TestMethod]
    public void NormalizeScore_NegativeRawScore_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));
    }

    [TestMethod]
    public void NormalizeScore_NegativeMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, -10.0));
    }
}

